import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  const [cars, setCars] = useState([]);
  const [brands, setBrands] = useState([]);
  const [selectedCar, setSelectedCar] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [carsRes, brandsRes] = await Promise.all([
        axios.get('http://localhost:5000/api/cars/featured'),
        axios.get('http://localhost:5000/api/brands')
      ]);
      setCars(carsRes.data);
      setBrands(brandsRes.data);
      setLoading(false);
    } catch (error) {
      console.error('Lỗi:', error);
      setLoading(false);
    }
  };

  const viewCarDetail = async (id) => {
    try {
      const res = await axios.get(`http://localhost:5000/api/cars/${id}`);
      setSelectedCar(res.data);
    } catch (error) {
      console.error('Lỗi:', error);
    }
  };

  const closeDetail = () => {
    setSelectedCar(null);
  };

  const formatPrice = (price) => {
    return price.toString().replace(/\B(?=(\d{3})+(?!\d))/g, '.') + ' ₫';
  };

  if (loading) {
    return <div className="loading">Đang tải dữ liệu...</div>;
  }

  return (
    <div className="app">
      {/* Header */}
      <header>
        <div className="container">
          <nav>
            <div className="logo">
              <h1>Auto<span>Vip</span></h1>
            </div>
            <ul className="nav-menu">
              <li><a href="#home">Trang Chủ</a></li>
              <li><a href="#cars">Xe</a></li>
              <li><a href="#brands">Thương Hiệu</a></li>
            </ul>
          </nav>
        </div>
      </header>

      {/* Hero Section */}
      <section id="home" className="hero">
        <div className="container">
          <div className="hero-content">
            <h1>Tìm Kiếm Xe Mơ Ước Của Bạn</h1>
            <p>Hơn 500+ mẫu xe cao cấp từ các thương hiệu hàng đầu</p>
          </div>
        </div>
      </section>

      {/* Featured Cars */}
      <section id="cars" className="featured-cars">
        <div className="container">
          <h2 className="section-title">Xe Nổi Bật</h2>
          <div className="car-grid">
            {cars.map(car => (
              <div key={car.id} className="car-card">
                <img src={car.image_url} alt={car.name} />
                <div className="car-info">
                  <h3>{car.name}</h3>
                  <p className="price">{formatPrice(car.price)}</p>
                  <div className="specs">
                    <span>📅 {car.year}</span>
                    <span>⛽ {car.fuel_type}</span>
                    <span>⚡ {car.speed} km/h</span>
                  </div>
                  <button onClick={() => viewCarDetail(car.id)} className="btn-detail">
                    Xem Chi Tiết
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Brands */}
      <section id="brands" className="brands">
        <div className="container">
          <h2 className="section-title">Thương Hiệu</h2>
          <div className="brand-grid">
            {brands.map((brand, index) => (
              <div key={index} className="brand-item">
                🚗 {brand.brand}
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Car Detail Modal */}
      {selectedCar && (
        <div className="modal">
          <div className="modal-content">
            <span className="close" onClick={closeDetail}>&times;</span>
            <h2>{selectedCar.name}</h2>
            <img src={selectedCar.image_url} alt={selectedCar.name} />
            <p><strong>Giá:</strong> {formatPrice(selectedCar.price)}</p>
            <p><strong>Hãng:</strong> {selectedCar.brand}</p>
            <p><strong>Năm:</strong> {selectedCar.year}</p>
            <p><strong>Nhiên liệu:</strong> {selectedCar.fuel_type}</p>
            <p><strong>Tốc độ:</strong> {selectedCar.speed} km/h</p>
            <p><strong>Mô tả:</strong> {selectedCar.description}</p>
          </div>
        </div>
      )}

      {/* Footer */}
      <footer>
        <div className="container">
          <div className="footer-content">
            <div className="footer-section">
              <h3>AutoVip</h3>
              <p>Showroom xe hơi cao cấp</p>
            </div>
            <div className="footer-section">
              <h4>Liên Hệ</h4>
              <p>📍 123 Nguyễn Văn Linh, Q7, TP.HCM</p>
              <p>📞 1900 1234</p>
              <p>✉️ info@autovip.com</p>
            </div>
          </div>
          <div className="footer-bottom">
            <p>&copy; 2024 AutoVip. All rights reserved.</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

export default App;
